<?php require 'vendor/autoload.php'; require 'bootstrap/app.php'; $app = app(); $app->make(Illuminate\Contracts\Console\Kernel::class)->bootstrap(); $books = App\Models\Book::with('items')->where('title', 'like', '%Cases in corporate financial reporting%')->get(); foreach($books as $book) { echo ID: $($book->id) - Title: $($book->title) - Copies: $($book->items->count())\n; foreach($book->items as $item) { echo  Barcode: $($item->item_code)\n; } }
